    pub fn handle_message(&self, mut client: Value, mut message: Value) {
        let mut channelId: Value = self.safe_string(message.clone(), Value::Int(0), &[]);
        //
        //     [
        //         1231,
        //         "hb",
        //     ]
        //
        // auth message
        //    {
        //        "event": "auth",
        //        "status": "OK",
        //        "chanId": 0,
        //        "userId": 3159883,
        //        "auth_id": "ac7108e7-2f26-424d-9982-c24700dc02ca",
        //        "caps": {
        //          "orders": { read: 1, write: 1 },
        //          "account": { read: 1, write: 1 },
        //          "funding": { read: 1, write: 1 },
        //          "history": { read: 1, write: 0 },
        //          "wallets": { read: 1, write: 1 },
        //          "withdraw": { read: 0, write: 1 },
        //          "positions": { read: 1, write: 1 },
        //          "ui_withdraw": { read: 0, write: 0 }
        //        }
        //    }
        //
        if is_true(&Value::Bool(is_array(&message))) {
            if is_equal(&get_value(&message, &Value::Int(1)), &Value::Str("hb".to_string())) {
                return;
            }
            let mut subscription: Value = self.safe_value(get_value(&client, &Value::Str("subscriptions".to_string())), channelId.clone(), &[Value::Map({
                let mut m = indexmap::IndexMap::new();
                m
            })]);
            let mut channel: Value = self.safe_string_k(subscription.clone(), "channel", &[]);
            let mut name: Value = self.safe_string(message.clone(), Value::Int(1), &[]);
            let mut publicMethods: Value = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("book".to_string(), Value::Null.clone());
                    m.insert("cs".to_string(), Value::Null.clone());
                    m.insert("candles".to_string(), Value::Null.clone());
                    m.insert("ticker".to_string(), Value::Null.clone());
                    m.insert("trades".to_string(), Value::Null.clone());
                m
            });
            let mut privateMethods: Value = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("os".to_string(), Value::Null.clone());
                    m.insert("ou".to_string(), Value::Null.clone());
                    m.insert("on".to_string(), Value::Null.clone());
                    m.insert("oc".to_string(), Value::Null.clone());
                    m.insert("wu".to_string(), Value::Null.clone());
                    m.insert("ws".to_string(), Value::Null.clone());
                    m.insert("tu".to_string(), Value::Null.clone());
                m
            });
            let mut method: Value = Value::Null;
            if is_equal(&channelId, &Value::Str("0".to_string())) {
                method = self.safe_value(privateMethods.clone(), name.clone(), &[]);
            }  else {
                method = self.safe_value2(publicMethods.clone(), name.clone(), channel.clone(), &[]);
            }
            if !is_equal(&method, &Value::Null) {
                method.call(&[client.clone(), message.clone(), subscription.clone()]);
            }
        }  else {
            let mut event: Value = self.safe_string_k(message.clone(), "event", &[]);
            if !is_equal(&event, &Value::Null) {
                let mut methods: Value = Value::Map({
                    let mut m = indexmap::IndexMap::new();
                        m.insert("info".to_string(), Value::Null.clone());
                        m.insert("subscribed".to_string(), Value::Null.clone());
                        m.insert("unsubscribed".to_string(), Value::Null.clone());
                        m.insert("auth".to_string(), Value::Null.clone());
                    m
                });
                let mut method: Value = self.safe_value(methods.clone(), event.clone(), &[]);
                if !is_equal(&method, &Value::Null) {
                    method.call(&[client.clone(), message.clone()]);
                }
            }
        }
}
